#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define ull unsigned long long
#define inf 0x3f3f3f3f
#define NoAns puts("-1")
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN = 1e3 + 5, dx[] = {1, 0, -1, 0}, dy[] = {0, 1, 0, -1};
int n, times = 0, cnt = 0, flag;
char a[MAXN][MAXN], tmp[MAXN][MAXN];
bool vis[MAXN][MAXN];
void dfs(int x, int y)
{
	vis[x][y] = true;
	for (int i = 0; i < 4; ++i)
	{
		if (x + dx[i] > 0 && x + dx[i] <= n && y + dy[i] <= n && y + dy[i] > 0 && a[x + dx[i]][y + dy[i]] == '#' && vis[x + dx[i]][y + dy[i]] == false)dfs(x + dx[i], y + dy[i]);
	}
}
int main(void)
{
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	memset(vis, 0, sizeof vis);
	cin >> n;
	for (int i = 1; i <= n; ++i)
	{
		for (int j = 1; j <= n; ++j)
		{
			cin >> a[i][j];
		}
	}
	for (int i = 1; i <= n; ++i)
	{
		for (int j = 1; j <= n; ++j)
		{
			if (a[i][j] == '.')continue;
			if (vis[i][j])continue;
			++cnt;
			dfs(i, j);
		}
	}
	memset(vis, 0, sizeof vis);
	for (int i = 1; i <= n; ++i)
	{
		for (int j = 1; j <= n; ++j)
		{
			if (a[i][j] == '.'||a[i + 1][j] == '.' || a[i][j + 1] == '.' || a[i - 1][j] == '.' || a[i][j - 1] == '.')continue;
			if (vis[i][j])continue;
			--cnt;
			dfs(i, j);
		}
	}
	cout << cnt;
	return false;
}
